files.search_replace_raw:
--- SEARCH
func isUnixAddrResolvable(fl FieldLevel) bool {
	addr := fl.Field().String()
	_, err := net.ResolveUnixAddr("unix", addr)
	if err != nil {
		return false
	}

	fileInfo, err := os.Stat(addr)
	if err != nil {
		return false
	}

	return fileInfo.Mode().Type() == fs.ModeSocket
}
+++ REPLACE
func isUnixAddrResolvable(fl FieldLevel) bool {
	addr := fl.Field().String()
	_, err := net.ResolveUnixAddr("unix", addr)
	if err != nil {
		return false
	}

	fileInfo, err := os.Stat(addr)
	if err != nil {
		return false
	}

	return !fileInfo.IsDir() && (fileInfo.Mode()&fs.ModeSocket) == fs.ModeSocket
}

